import 'package:flutter/material.dart'; import '../theme/app_theme.dart'; class DeviceTypeIcon extends StatelessWidget { final String type; final double size; const DeviceTypeIcon({super.key, required this.type, this.size = 24}); @override Widget build(BuildContext context) { IconData icon; switch (type) { case 'tablet': icon = Icons.tablet_android_rounded; break; case 'laptop': icon = Icons.laptop_rounded; break; case 'desktop': icon = Icons.desktop_windows_rounded; break; default: icon = Icons.smartphone_rounded; } return Icon(icon, color: AppTheme.primaryColor, size: size); } }